// // This is a 1-to-2 demultiplexer. Selecting 'b' when 'sel' is 0 and 'a' when 'sel' is 1.
module mux_2to1(
    input a,     // First input signal.
    input b,     // Second input signal.
    input sel,   // Select signal.

    output y     // Output signal.
);

//------------------------------------------------
// 2-to-1 multiplexer logic
assign y = sel ? b : a;

endmodule
